 1	import * as React from 'react';
 2	import { Tooltip } from '@patternfly/react-core';
 3	import { BUILDER_NODE_ADD_RADIUS } from './const';
 4	import InstallingNodeDecorator from './InstallingNodeDecorator';
 5	
 6	import './LoadingTask.scss';
 7	import { truncateMiddle } from './truncate-middle';
 8	import { t } from '../utils/common-utils';
 9	
10	type LoadingTaskProps = {
11	  width: number;
12	  height: number;
13	  name: string;
14	};
15	
16	const LoadingTask: React.FC<LoadingTaskProps> = ({ width, height, name }) => {
17	  const textRef = React.useRef();
18	  const truncatedName = React.useMemo(
19	    () => truncateMiddle(name, { length: 10, truncateEnd: true }),
20	    [name],
21	  );
22	  return (
23	    <g>
24	      <rect
25	        width={width}
26	        height={height}
27	        rx={15}
28	        className={'opp-pipeline-vis-loading-node'}
29	      />
30	      <g>
31	        <InstallingNodeDecorator
32	          x={0}
33	          y={BUILDER_NODE_ADD_RADIUS / 4}
34	          content={t('Installing')}
35	        />
36	      </g>
37	      <Tooltip triggerRef={textRef} content={name}>
38	        <text
39	          ref={textRef}
40	          className="opp-pipeline-vis-loading-node__name"
41	          x={width / 2}
42	          y={height / 2 + 1}
43	        >
44	          {truncatedName}
45	        </text>
46	      </Tooltip>
47	    </g>
48	  );
49	};
50	
51	export default LoadingTask;

